<template><SolutionDesignNodeLayout :workflow="workflow" :node="currentNode" :loading="context.solutionDesignLoading" :error-message="context.solutionDesignErrorMessage"><SolutionUploadSlots :slots="slots" :is-pending="isPending" @upload="handleUpload" @download="downloadUpload"/><section v-if="flow" class="quotation-section"><h4>报价/投标</h4><el-tag>{{flow.branchStatus||'待选择'}}</el-tag><div class="action-row"><el-button v-if="flow.permissions?.canSelectBranch" type="primary" :loading="isPending('branch:quotation')" @click="selectBranch('quotation')">选择报价流程</el-button><el-button v-if="flow.permissions?.canSelectBranch" :loading="isPending('branch:tender')" @click="selectBranch('tender')">选择投标流程</el-button><el-button v-if="flow.permissions?.canSubmitQuotation" type="primary" :loading="isPending('quotation:submit')" @click="submitQuotation">提交报价单</el-button><el-button v-if="flow.permissions?.canSubmitTender" type="primary" :loading="isPending('submit:quotation_or_tender')" @click="submitNode(nodeKey)">提交投标审批</el-button><el-button v-if="flow.permissions?.canAcceptQuotation" type="success" :loading="isPending('quotation:accept')" @click="acceptQuotation">客户接受报价</el-button></div><el-form v-if="flow.permissions?.canRejectQuotationToRdCost||flow.permissions?.canRejectQuotationAndEndProject" label-position="top"><el-form-item label="客户不接受原因"><el-input v-model="quotationReturnReason" type="textarea" :rows="3"/></el-form-item><el-form-item label="处理方式"><el-select v-model="quotationRejectAction"><el-option label="退回研发成本估算" value="return_to_rd_cost"/><el-option label="结束项目" value="end_project"/></el-select></el-form-item><el-button type="danger" plain :loading="isPending(`quotation:reject:${quotationRejectAction}`)" @click="rejectQuotation">客户不接受并处理</el-button></el-form></section><SolutionNodeActions v-if="currentNode" :node="currentNode" :is-pending="isPending" :return-reason="returnReasons[nodeKey]||''" @update:return-reason="returnReasons[nodeKey]=$event" @submit="submitNode(nodeKey)" @approve="approveNode(nodeKey)" @return="returnNode(nodeKey)"/></SolutionDesignNodeLayout></template><script setup>import {computed} from 'vue'; import SolutionDesignNodeLayout from '../../../components/project-workspace/solution-design/SolutionDesignNodeLayout.vue'; import SolutionUploadSlots from '../../../components/project-workspace/solution-design/SolutionUploadSlots.vue'; import SolutionNodeActions from '../../../components/project-workspace/solution-design/SolutionNodeActions.vue'; import {solutionDesignNodePageProps,useSolutionDesignNodePage} from '../../../composables/project-stage/solution-design/useSolutionDesignNodePage.js'; const emit=defineEmits(['business-state-changed']); const props=defineProps(solutionDesignNodePageProps); const {context,workflow,nodeKey,currentNode,slots,localMessage,localError,returnReasons,quotationReturnReason,quotationRejectAction,isPending,handleUpload,downloadUpload,submitNode,approveNode,returnNode,selectBranch,submitQuotation,acceptQuotation,rejectQuotation}=useSolutionDesignNodePage(props,emit); const flow=computed(()=>workflow.value?.quotationTender||null);</script>
